{
  "name": "analysing/analytics",
  "description": "Analysing process app",
  "type": "project",
  "license": "proprietary",
  "authors": [
    {
      "name": "Oleksandr Tishchenko",
      "email": "dev@highhopesamerica.com"
    }
  ],
  "require": {
    "php": "^8.4",
    "symfony/framework-bundle": "^6.3 || ^7.0",
    "symfony/console": "^6.3 || ^7.0",
    "symfony/http-foundation": "^6.3 || ^7.0",
    "symfony/http-client": "^6.3 || ^7.0",
    "symfony/dependency-injection": "^6.3 || ^7.0",
    "doctrine/orm": "^2.15 || ^3.0",
    "doctrine/dbal": "^3.6",
    "psr/log": "^3.0"
  },
  "require-dev": {
    "phpunit/phpunit": "^10.4",
    "phpstan/phpstan": "^1.11",
    "friendsofphp/php-cs-fixer": "^3.20",
    "symfony/var-dumper": "^6.3 || ^7.0"
  },
  "autoload": {
    "psr-4": {
      "App\\": "src/"
    }
  },
  "autoload-dev": {
    "psr-4": {
      "App\\Tests\\": "tests/"
    }
  },
  "scripts": {
    "scan": "php tools/analytics-scan-layer-map.php",
    "lint:canon": "php tools/analytics-scan-layer-map.php",
    "guard:interfaceinterface": "php tools/analytics-interfaceinterface-guard.php",
    "guard:namespace": "php tools/analytics-namespace-guard.php --mode=report",
    "qa:env": "php tools/qa/AnalyticsQaEnvironmentCheck.php",
    "test": [
      "@qa:env",
      "phpunit"
    ],
    "analyse": "phpstan analyse src --level=max",
    "fix": "php-cs-fixer fix --allow-risky=yes",
    "clean:config-garbage": "php tools/analytics-config-garbage-clean.php",
    "purge:interfaceinterface": "php tools/analytics-interfaceinterface-purge.php",
    "guard:domain-hygiene": "php tools/analytics-domain-hygiene-guard.php",
    "guard:php-header": "php tools/analytics-php-header-guard.php"
  },
  "config": {
    "sort-packages": true,
    "optimize-autoloader": true
  }
}
